CREATE TABLE `cash` (
  `id` int(11) NOT NULL,
  `doctorId` int(11) DEFAULT NULL,
  `clientId` int(11) NOT NULL,
  `sum` int(11) DEFAULT NULL,
  `discount` int(11) NOT NULL DEFAULT 0,
  `date` datetime NOT NULL,
  `payment` varchar(255) DEFAULT NULL,
  `status` varchar(255) NOT NULL DEFAULT 'debt',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `analise` varchar(255) DEFAULT NULL,
  `benefits` varchar(255) DEFAULT NULL,
  `appeal` varchar(255) DEFAULT NULL,
  `registratorId` int(11) DEFAULT NULL,
  `totalAmount` int(11) NOT NULL DEFAULT 0,
  `discountPercent` float DEFAULT NULL,
  `finalAmount` int(11) NOT NULL DEFAULT 0,
  `paidAmount` int(11) NOT NULL DEFAULT 0,
  `debtAmount` int(11) NOT NULL DEFAULT 0,
  `paymentMethod` varchar(255) NOT NULL DEFAULT 'cash',
  `paymentDetails` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`paymentDetails`)),
  `servicesDescription` text DEFAULT NULL,
  `labAnalyses` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`labAnalyses`)),
  `promoCode` varchar(255) DEFAULT NULL,
  `benefitCategory` varchar(255) DEFAULT NULL,
  `fiscalReceipt` varchar(255) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `debt` int(11) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

