  `republic` varchar(255) DEFAULT NULL,
  `region` varchar(255) DEFAULT NULL,
  `street` varchar(255) DEFAULT NULL,
  `addres` varchar(255) DEFAULT NULL,
  `passportSeries` varchar(255) DEFAULT NULL,
