--
-- Структура таблицы `labs`
--

CREATE TABLE `labs` (
  `id` int(11) NOT NULL,
  `name` varchar(255) DEFAULT NULL,
  `price` varchar(255) DEFAULT NULL,
  `about` varchar(255) DEFAULT NULL,
  `table` varchar(255) DEFAULT NULL,
  `analise` varchar(255) NOT NULL,
  `ready` tinyint(1) NOT NULL DEFAULT 0,
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `clientId` int(11) DEFAULT NULL,
  `labId` int(11) DEFAULT NULL,
  `testCode` varchar(50) DEFAULT NULL,
  `result` varchar(255) DEFAULT NULL,
  `unit` varchar(50) DEFAULT NULL,
  `referenceMin` float DEFAULT NULL,
  `referenceMax` float DEFAULT NULL,
  `referenceText` varchar(255) DEFAULT NULL,
  `method` varchar(255) DEFAULT NULL,
  `sampleType` varchar(100) DEFAULT 'Кровь (сыворотка)',
  `conclusion` text DEFAULT NULL,
  `isAbnormal` tinyint(1) DEFAULT 0,
  `readyDate` datetime DEFAULT NULL,
  `executedBy` varchar(255) DEFAULT NULL,
  `categoryId` int(11) DEFAULT NULL,
  `priority` enum('routine','urgent','stat') DEFAULT 'routine',
  `notes` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

